CREATE TABLE IF NOT EXISTS p(c3 NUMERIC CHECK (CURRENT_TIME IN (SELECT * LIMIT CURRENT_DATE IN (SELECT * LIMIT TRUE IN (SELECT * LIMIT TRUE IN (SELECT * LIMIT CURRENT_DATE IN (SELECT * LIMIT NULL IN (SELECT * EXCEPT SELECT * FROM p NOT INDEXED WHERE NULL GROUP BY FALSE WINDOW w1 AS () ORDER BY NULL DESC NULLS FIRST, CURRENT_DATE COLLATE NOCASE ASC NULLS FIRST))))))));
CREATE VIEW IF NOT EXISTS v1 AS SELECT *;
EXPLAIN QUERY PLAN SELECT *;